function detectFanFuYin(natal_pillar, transit_pillar) {
  const stemClash = STEM_CLASH[natal_pillar.stem] === transit_pillar.stem;
  const branchClash = BRANCH_CLASH[natal_pillar.branch] === transit_pillar.branch;
  const stemSame = natal_pillar.stem === transit_pillar.stem;
  const branchSame = natal_pillar.branch === transit_pillar.branch;
  if (stemClash && branchClash) return 'fan_yin';
  if (stemSame && branchSame) return 'fu_yin';
  return null;
}

