function getDHHS(birthDate, monthBranch) {
  const monthStart = getMonthSolarTermBoundary(birthDate);
  const daysIntoMonth = (birthDate - monthStart) / 86400000;
  const hidden = HIDDEN_STEMS[monthBranch];
  // Find which sub-period
  if (daysIntoMonth < hidden[0].days) return hidden[0].stem; // residual qi
  if (daysIntoMonth < hidden[0].days + hidden[1].days) return hidden[1].stem; // middle qi
  return hidden[2].stem; // main qi
}
